#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const int N = 3e5+5;
struct node{
    int opt,id,x,y,k;
}q[N],q1[N],q2[N];
int n,m,Q,qans,yac[N];
int Ls[N],lscnt;
vector<int> g[N];
int Fa[N],dep[N];
int sz[N],wc[N];
int top[N],dfn[N],dfncnt,fd[N];
int tr[N];
int ans[N];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void DFS1(int u,int fa){
    Fa[u]=fa,sz[u]=1;
    dep[u]=dep[fa]+1;
    for(int v:g[u])if(v^fa){
        DFS1(v,u),sz[u]+=sz[v];
        if(sz[v]>sz[wc[u]])wc[u]=v;
    }return;
}
void DFS2(int u,int Top){
    top[u]=Top;
    dfn[u]=++dfncnt,fd[dfncnt]=u;
    if(wc[u])DFS2(wc[u],Top);
    for(int v:g[u])
        if(v^Fa[u]&&v^wc[u])DFS2(v,v);return;
}
void upd(int x,int k){while(x<=n)tr[x]+=k,x+=x&-x;return;}
int ask(int x){int sum=0;while(x)sum+=tr[x],x-=x&-x;return sum;}
int query(int x,int y){
    int res=0;
    while(top[x]!=top[y]){
        if(dfn[top[x]]<dfn[top[y]])swap(x,y);
        res+=ask(dfn[x])-ask(dfn[top[x]]-1);
        x=Fa[top[x]];
    }if(dfn[x]>dfn[y])swap(x,y);
    res+=ask(dfn[y])-ask(dfn[x]-1);
    return res;
}
void solve(int l,int r,int L,int R){
    if(L>R)return;bool can=0;
    for(int i=L;i<=R;i++)if(q[i].opt==2)can=1;
    if(!can)return;
    if(l==r){
        for(int i=L;i<=R;i++)
            if(q[i].opt==2)ans[q[i].id]=Ls[l];
        return;
    }
    int mid=(l+r)>>1,p1=0,p2=0;
    for(int i=L;i<=R;i++)
        if(q[i].opt==1){
            if(q[i].k>mid)
                upd(dfn[q[i].id],q[i].y),
                q2[++p2]=q[i];
            else q1[++p1]=q[i];
        }else{
            int tmp=query(q[i].x,q[i].y);
            if(tmp>=q[i].k)q2[++p2]=q[i];
            else q[i].k-=tmp,q1[++p1]=q[i];
        }
    for(int i=1;i<=p2;i++)
        if(q2[i].opt==1)upd(dfn[q2[i].id],-q2[i].y);
    for(int i=1;i<=p1;i++)q[L+i-1]=q1[i];
    for(int i=1;i<=p2;i++)q[R-p2+i]=q2[i];
    solve(l,mid,L,L+p1-1);
    solve(mid+1,r,R-p2+1,R);return;
}
int main(){
    n=read(),m=read();
    for(int i=1;i<=n;i++){
        yac[i]=read();
        q[++Q]={1,i,0,1,yac[i]};
        Ls[++lscnt]=yac[i];
    }
    for(int i=1;i<n;i++){
        int x=read(),y=read();
        g[x].pb(y),g[y].pb(x);
    }
    DFS1(1,0),DFS2(1,0);
    for(int i=1;i<=m;i++){
        int k=read(),x=read(),y=read();
        if(!k){
            q[++Q]={1,x,0,-1,yac[x]};
            yac[x]=y;
            q[++Q]={1,x,0,1,yac[x]};
            Ls[++lscnt]=y;
        }else q[++Q]={2,++qans,x,y,k};
    }
    sort(Ls+1,Ls+lscnt+1);
    lscnt=unique(Ls+1,Ls+lscnt+1)-Ls-1;
    for(int i=1;i<=Q;i++)if(q[i].opt==1)
        q[i].k=lower_bound(Ls+1,Ls+lscnt+1,q[i].k)-Ls;
    solve(0,lscnt+1,1,Q);
    for(int i=1;i<=qans;i++)
        if(ans[i]==0)cout<<"invalid request!\n";
        else cout<<ans[i]<<"\n";
    return 0;
}
